function pwStrength(pw) {
    if (!pw) return {
        score: 0,
        label: "",
        color: ""
    };
    let s = 0;
    if (pw.length >= 8) s++;
    if (pw.length >= 12) s++;
    if (/[A-Z]/.test(pw)) s++;
    if (/[0-9]/.test(pw)) s++;
    if (/[^A-Za-z0-9]/.test(pw)) s++;
    if (s <= 1) return {
        score: 1,
        label: "Weak",
        color: "#ef4444"
    };
    if (s <= 2) return {
        score: 2,
        label: "Fair",
        color: "#f97316"
    };
    if (s <= 3) return {
        score: 3,
        label: "Good",
        color: "#eab308"
    };
    if (s <= 4) return {
        score: 4,
        label: "Strong",
        color: "#22c55e"
    };
    return {
        score: 5,
        label: "Excellent",
        color: "#10b981"
    };
}
